def gen(rng, size):
    n = max(1, min(size, 50))
    s = ''.join(rng.choice('abcdefghijklmnopqrstuvwxyz') for _ in range(n))
    dict_size = rng.randint(1, min(50, max(1, n)))
    dictionary = set()
    attempts = 0
    while len(dictionary) < dict_size and attempts < 200:
        attempts += 1
        if n >= 2:
            i = rng.randint(0, n - 1)
            j = rng.randint(i + 1, n)
            word = s[i:j]
        else:
            word = s
        if 1 <= len(word) <= 50:
            dictionary.add(word)
    if not dictionary:
        dictionary.add(s[:1] if s else 'a')
    return [s, list(dictionary)]

