class Solution:
    def minExtraChar(self, s, dictionary):
        words = set(dictionary)
        n = len(s)
        dp = [0] * (n + 1)
        for i in range(n - 1, -1, -1):
            dp[i] = dp[i + 1] + 1
            for j in range(i + 1, n + 1):
                if s[i:j] in words and dp[j] < dp[i]:
                    dp[i] = dp[j]
        return dp[0]

