var minExtraChar = function(s, dictionary) {
    const words = new Set(dictionary);
    const n = s.length;
    const dp = new Array(n + 1).fill(0);
    for (let i = n - 1; i >= 0; i--) {
        dp[i] = dp[i + 1] + 1;
        for (let j = i + 1; j <= n; j++) {
            if (words.has(s.slice(i, j)) && dp[j] < dp[i]) {
                dp[i] = dp[j];
            }
        }
    }
    return dp[0];
};
